              <span className="font-black text-xl tracking-tight text-slate-900 dark:text-white">SHARUN</span>
              <span className="text-[10px] font-bold tracking-[0.2em] text-blue-600 dark:text-blue-400">PRODUCT LEAD</span>
            </div>
          </button>

          <div className="hidden md:flex items-center gap-10">
            {['About', 'Methodology', 'Work', 'Skills'].map((item) => (
              <button
                key={item}
                onClick={() => handleScrollTo(item.toLowerCase())}
                className="text-xs font-bold uppercase tracking-widest text-slate-600 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
