              {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile menu */}
      {isOpen && (
        <div className="md:hidden bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 animate-slide-in">
          <div className="px-6 py-8 space-y-4">
            {['About', 'Methodology', 'Work', 'Skills', 'Contact'].map((item) => (
              <button
                key={item}
                onClick={() => handleScrollTo(item.toLowerCase())}
                className="block w-full text-left py-4 text-lg font-bold text-slate-900 dark:text-white border-b border-slate-100 dark:border-slate-900"
