             <div className="flex items-center gap-2 text-slate-500 dark:text-slate-500">
                <ShieldCheck className="w-5 h-5 text-emerald-500" />
                <span className="text-sm font-semibold tracking-wide">Enterprise Grade</span>
             </div>
             <div className="flex items-center gap-2 text-slate-500 dark:text-slate-500">
                <Rocket className="w-5 h-5 text-orange-500" />
                <span className="text-sm font-semibold tracking-wide">Rapid Deployment</span>
             </div>
             <div className="flex items-center gap-2 text-slate-500 dark:text-slate-500">
                <Zap className="w-5 h-5 text-yellow-500" />
                <span className="text-sm font-semibold tracking-wide">Agile Expert</span>
             </div>
          </div>

          {/* High-Impact Actions */}
          <div className="flex flex-col sm:flex-row gap-5 justify-center mb-24 reveal" style={{ animationDelay: '500ms' }}>
            <button 
              onClick={() => scrollToSection('work')}
              className="group relative inline-flex items-center justify-center px-8 py-4 font-bold text-white transition-all duration-300 bg-blue-600 rounded-xl hover:bg-blue-700 hover:scale-[1.02] active:scale-95 shadow-lg shadow-blue-500/25"
            >
              <span>Explore Strategic Impact</span>
              <ArrowRight className="ml-2 w-5 h-5 transition-transform group-hover:translate-x-1" />
            </button>
            <button 
              onClick={() => scrollToSection('contact')}
              className="inline-flex items-center justify-center px-8 py-4 font-bold text-slate-700 dark:text-white transition-all duration-300 bg-white/80 dark:bg-slate-800/40 border border-slate-200 dark:border-slate-700 rounded-xl hover:bg-white dark:hover:bg-slate-700/60 backdrop-blur-md hover:scale-[1.02] active:scale-95"
            >
              Consultation Inquiry
            </button>
          </div>

          {/* Monochrome Trust Bar */}
          <div className="pt-12 border-t border-slate-200/50 dark:border-slate-800/50 reveal" style={{ animationDelay: '600ms' }}>
            <p className="text-[10px] uppercase tracking-[0.4em] font-black text-slate-400 dark:text-slate-600 mb-10">Global Delivery Partnerships</p>
            <div className="flex flex-wrap justify-center items-center gap-x-16 gap-y-10">
              {CLIENT_LOGOS.map((client) => (
                <img 
                  key={client.name}
                  src={client.logoUrl} 
                  alt={client.name}
                  className="h-6 md:h-8 w-auto grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all duration-500 cursor-help dark:invert"
                  title={client.name}
                />
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Floating Scroll Indicator */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 hidden lg:flex flex-col items-center gap-2 text-slate-300 dark:text-slate-700 animate-float pointer-events-none">
        <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Scroll</span>
        <ChevronDown className="w-5 h-5" />
      </div>
    </section>
  );
};

export default Hero;
